function sectDisplayNameFor(sectKey){
  return (SECTS[sectKey] && SECTS[sectKey].name) || (COMING_SOON_SECTS.find(s=>s.key===sectKey)||{}).name || sectKey;
}

// 依「一內」的屬性主軸（同兩個簽名主屬性、同屬性門派）自動生成二內～六內的佔位資質，
// 數值隨心法等級遞增，之後要幫某一本寫真正的資質／特效時，直接改 INTERNAL_POOL 裡對應物件的欄位。
Object.entries(ADVANCED_INTERNAL_NAMES).forEach(([sectKey, names])=>{
  const base = INTERNAL_POOL.find(t=>t.id===STARTER_INTERNAL_ID[sectKey]);
  if(!base) return;
  const stats = Object.keys(base.bonusStat);
  names.forEach((name, idx)=>{
    const rank = idx+2; // 二內=2 ... 六內=6
    const growth = 1 + (rank-1)*0.35;
    const bonusStat = {};
    stats.forEach(k=>{ bonusStat[k] = Math.round(base.bonusStat[k]*growth); });
    INTERNAL_POOL.push({
      id:`${sectKey}_${rank}`, name, sect:sectKey, affinity:base.affinity,
      bonusStat,
      powerMult:Math.round(base.powerMult*(1+(rank-1)*0.03)*100)/100,
      hpMult:Math.round(base.hpMult*(1+(rank-1)*0.02)*100)/100,
      mpMult:Math.round(base.mpMult*(1+(rank-1)*0.02)*100)/100,
      defMult:Math.round(base.defMult*(1+(rank-1)*0.02)*100)/100,
      special:null, specialValue:null,
      desc:`${sectDisplayNameFor(sectKey)}門派進階心法（${rank}內），效果待補。`,
    });
  });
});

// 每門心法各層（1～36）的具體效果，是「練到第幾層」的唯一數值來源。每一層有：
//   1) bonusStat —— 直接加五大主屬性（臂力／身法／內息／罡氣／體魄），練到那層就拿到那層的數字。
//   2) hpBonus／mpBonus —— 直接加氣血／內力上限的絕對數值（不是倍率）。
//   3) desc —— 這一層的特效文字說明。UI 會照這段文字顯示，但目前戰鬥引擎還沒有「機率觸發、
//      持續數回合的狀態效果」這套通用系統，所以這些特效文字暫時只是展示用，還不會真的在
//      戰鬥中發動（沒寫 desc 的層數會退回 special，那是舊版少數幾門心法已經接好邏輯的固定被動）。
// 下面的 buildInternalLayers() 只是先生成一組佔位數值：主屬性以心法本身定義的「簽名主屬性」
// （skill.bonusStat 裡本來就有的 1～2 個屬性）為主、其餘屬性給少量陪襯成長，36 層線性遞增，
// hpBonus/mpBonus 佔位一律是 0。接著 AUTHORED_LAYERS（見下面）會覆寫掉已經真正設計過的心法。
// 之後要幫某一層寫真正的內容時，直接改 AUTHORED_LAYERS 裡對應心法/層數的物件就好。
const PRIMARY_STAT_KEYS = ["臂力","身法","內息","罡氣","體魄"];
function buildInternalLayers(skill){
  const signature = Object.entries(skill.bonusStat||{});
  const signatureAvg = signature.length>0 ? signature.reduce((s,[,v])=>s+v,0)/signature.length : 0;
  const target = {};
  PRIMARY_STAT_KEYS.forEach(k=>{
    const sig = skill.bonusStat && skill.bonusStat[k];
    target[k] = sig!=null ? sig : Math.round(signatureAvg*0.3);
  });
  return TIER_TABLE.map((row, i)=>{
    const frac = (i+1)/36; // 36 層線性成長，目前只有前 6 層（frac 最高到 6/36）能實際練到
    const bonusStat = {};
    PRIMARY_STAT_KEYS.forEach(k=>{ if(target[k]>0) bonusStat[k] = Math.round(target[k]*frac); });
    return {bonusStat, hpBonus:0, mpBonus:0, special:skill.special||null, specialValue:skill.specialValue||null, desc:null};
  });
}
INTERNAL_POOL.forEach(skill=>{ skill.layers = buildInternalLayers(skill); });

