// 已經真正設計過的心法，逐層覆寫掉上面的佔位資料（來自使用者的 idle武俠.xlsx 試算表）。
// 每一層：bonusStat 直接加五大主屬性、hpBonus／mpBonus 直接加氣血／內力上限（絕對數值，不是倍率），
// desc 是這一層的特效文字說明（機率觸發、有持續回合的狀態效果——UI 會顯示，但戰鬥引擎目前還沒有
// 對應的機率觸發／持續狀態系統可以真正執行這些效果，之後要做成真的會發動時再另外接上 combat.js）。
Object.entries(AUTHORED_LAYERS).forEach(([id, layers])=>{
  const skill = INTERNAL_POOL.find(t=>t.id===id);
  if(!skill) return;
  layers.forEach((authored, i)=>{ Object.assign(skill.layers[i], authored); });
});
